solution_code:
#include <iostream>

int main() {
    int threshold;
    std::cin >> threshold;

    auto shouldInclude = [threshold](int x) { return x > threshold; };

    int n;
    std::cin >> n;

    int sum = 0;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        if (shouldInclude(val)) sum += val;
    }

    std::cout << "FilteredSum: " << sum << "\n";
    return 0;
}

