solution_code:
#include <iostream>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int a, b;
    std::cin >> a >> b;
    std::cout << "GCD: " << gcd(a, b) << "\n";
    return 0;
}
